$output = "D:\eslam m h\programming\my projects\DUNAS TRAVEL\src\data\programs.json"

$entries = @()

# Helper to add a program
function Add-Program {
    param($p)
    $script:entries += $p
}

# ===== PROGRAM 1: REG-01 =====
Add-Program @{
    id = "REG-01"
    code = @{ ar = "REG-01 A (بالحافلة) / REG-01B (بالقطار السريع)"; en = "REG-01 A (by bus) / REG-01B (by high-speed train)"; es = "REG-01 A (en autobús) / REG-01B (en tren de alta velocidad)"; it = "REG-01 A (in pullman) / REG-01B (in treno ad alta velocità)"; pt = "REG-01 A (de ônibus) / REG-01B (de trem de alta velocidade)" }
    name = @{ ar = "تركيا الأسطورية"; en = "Legendary Turkey"; es = "Turquía Legendaria"; it = "Turchia Leggendaria"; pt = "Turquia Lendária" }
    duration = @{ ar = "11 أيام / 10 ليالٍ"; en = "11 days / 10 nights"; es = "11 días / 10 noches"; it = "11 giorni / 10 notti"; pt = "11 dias / 10 noites" }
    minPax = @{ ar = "فردان"; en = "2 Pax"; es = "2 Pax"; it = "2 Pax"; pt = "2 Pax" }
    overview = @{
        ar = "رحلة برية شاملة مصممة لعشاق التاريخ والطبيعة. تأخذك في مغامرة ممتدة تربط بين عراقة إسطنبول وعمق العاصمة أنقرة، لتصل إلى عجائب كابادوكيا والمدرجات الحرارية في باموكالي، مروراً بأطلال أفسس وطروادة وبورصة، وهي الرحلة الكلاسيكية المتكاملة لاستكشاف تاريخ الأناضول."
        en = "A comprehensive overland journey designed for history and nature lovers. It takes you on an extended adventure connecting the ancient heritage of Istanbul with the depths of the capital Ankara, reaching the wonders of Cappadocia and the thermal terraces of Pamukkale, passing through the ruins of Ephesus, Troy and Bursa — the complete classic tour to explore the history of Anatolia."
        es = "Un viaje terrestre integral diseñado para amantes de la historia y la naturaleza. Te lleva en una aventura prolongada que conecta la historia de Estambul con la profunda capital Ankara, hasta las maravillas de Capadocia y las terrazas termales de Pamukkale, pasando por las ruinas de Éfeso, Troya y Bursa — el recorrido clásico completo para explorar la historia de Anatolia."
        it = "Un viaggio via terra completo progettato per gli amanti della storia e della natura. Ti porta in un'avventura che collega l'antica Istanbul con la capitale Ankara, fino alle meraviglie della Cappadocia e alle terrazze termali di Pamukkale, passando per le rovine di Efeso, Troia e Bursa — il classico tour completo per esplorare la storia dell'Anatolia."
        pt = "Uma viagem terrestre abrangente projetada para amantes da história e da natureza. Leva você em uma aventura que conecta a história de Istambul com a capital Ancara, até as maravilhas da Capadócia e os terraços termais de Pamukkale, passando pelas ruínas de Éfeso, Troia e Bursa — o roteiro clássico completo para explorar a história da Anatólia."
    }
    highlights = @{
        ar = @("الانتقال السريع بقطار فائق السرعة إلى العاصمة أنقرة (في باقة REG-01B).","استكشاف المدن البيزنطية والمسيحية المحفورة بالكامل تحت الأرض في كابادوكيا.","السير على طبقات الجير الأبيض الساحرة في ""قلعة القطن"" باموكالي.","رؤية آثار طروادة التاريخية واسترجاع أحداث إلياذة هوميروس.","عبور جسر عثمان غازي المعلق، رابع أطول جسر معلق في العالم.")
        en = @("High-speed train transfer to the capital Ankara (in REG-01B package).","Exploring the Byzantine and Christian cities carved entirely underground in Cappadocia.","Walking on the enchanting white travertine terraces of Pamukkale (""Cotton Castle"").","Seeing the historical ruins of Troy and reliving Homer's Iliad.","Crossing the Osman Gazi suspension bridge, the 4th longest suspension bridge in the world.")
        es = @("Traslado en tren de alta velocidad a la capital Ankara (en el paquete REG-01B).","Exploración de las ciudades bizantinas y cristianas excavadas completamente bajo tierra en Capadocia.","Caminar sobre las encantadoras terrazas de travertino blanco de Pamukkale (""Castillo de Algodón"").","Ver las ruinas históricas de Troya y revivir la Ilíada de Homero.","Cruzar el puente colgante Osman Gazi, el 4º puente colgante más largo del mundo.")
        it = @("Trasferimento in treno ad alta velocità per la capitale Ankara (nel pacchetto REG-01B).","Esplorazione delle città bizantine e cristiane interamente scavate nel sottosuolo in Cappadocia.","Camminare sulle incantevoli terrazze di travertino bianco di Pamukkale (""Castello di Cotone"").","Vedere le rovine storiche di Troia e rivivere l'Iliade di Omero.","Attraversare il ponte sospeso Osman Gazi, il 4° ponte sospeso più lungo del mondo.")
        pt = @("Transferência de trem de alta velocidade para a capital Ancara (no pacote REG-01B).","Exploração das cidades bizantinas e cristãs totalmente escavadas no subsolo na Capadócia.","Caminhar sobre os encantadores terraços de travertino branco de Pamukkale (""Castelo de Algodão"").","Ver as ruínas históricas de Troia e reviver a Ilíada de Homero.","Atravessar a ponte suspensa Osman Gazi, a 4ª ponte suspensa mais longa do mundo.")
    }
    days = @(
        @{ day = "1"; meals = @{ ar = "وجبات بالفندق"; en = "Meals at hotel"; es = "Comidas en el hotel"; it = "Pasti in hotel"; pt = "Refeições no hotel" }; description = @{ ar = "الوصول لمطار إسطنبول، الاستقبال والانتقال للفندق والمبيت."; en = "Arrival at Istanbul Airport, reception and transfer to hotel. Overnight."; es = "Llegada al aeropuerto de Estambul, recepción y traslado al hotel. Alojamiento."; it = "Arrivo all'aeroporto di Istanbul, accoglienza e trasferimento in hotel. Pernottamento."; pt = "Chegada ao aeroporto de Istambul, recepção e transfer para o hotel. Pernoitada." } }
        @{ day = "2"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "جولة تشمل أسوار قسطنطينية القديمة، ومسجد رستم باشا، وبازار التوابل المصري. (متاح رحلة اختيارية بعد الظهر باسم ""لؤلؤة إسطنبول"" تشمل جولة البوسفور، ساحة تقسيم، شارع استقلال، وبرج غالاطا خارجي)."; en = "Tour including the ancient Walls of Constantinople, Rüstem Pasha Mosque, and the Egyptian Spice Bazaar. (Optional afternoon tour ""Pearl of Istanbul"" including Bosphorus cruise, Taksim Square, Istiklal Street, and Galata Tower exterior)."; es = "Recorrido que incluye las antiguas Murallas de Constantinopla, la Mezquita de Rüstem Pasha y el Bazar de las Especias. (Tarde opcional ""Perla de Estambul"" con crucero por el Bósforo, plaza Taksim, calle Istiklal y Torre de Gálata exterior)."; it = "Giro che include le antiche Mura di Costantinopoli, la Moschea di Rüstem Pasha e il Bazar delle Spezie. (Pomeriggio opzionale ""Perla di Istanbul"" con crociera sul Bosforo, piazza Taksim, via Istiklal e Torre di Galata esterno)."; pt = "Tour incluindo as antigas Muralhas de Constantinopla, a Mesquita de Rüstem Pasha e o Bazar de Especiarias. (Tarde opcional ""Pérola de Istambul"" com cruzeiro no Bósforo, Praça Taksim, Rua Istiklal e Torre de Gálata exterior)." } }
        @{ day = "3"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "زيارة الجراند بازار صباحاً، ثم التحرك بالحافلة (6 ساعات) أو القطار سريع السرعة (5 ساعات) إلى أنقرة. زيارة ضريح أتاتورك ثم العشاء والمبيت."; en = "Visit the Grand Bazaar in the morning, then travel by bus (6 hrs) or high-speed train (5 hrs) to Ankara. Visit Anıtkabir (Atatürk's Mausoleum), then dinner and overnight."; es = "Visita al Gran Bazar por la mañana, luego viaje en autobús (6 h) o tren de alta velocidad (5 h) a Ankara. Visita al Anıtkabir (Mausoleo de Atatürk), cena y alojamiento."; it = "Visita al Gran Bazar al mattino, poi viaggio in pullman (6 h) o treno ad alta velocità (5 h) per Ankara. Visita all'Anıtkabir (Mausoleo di Atatürk), cena e pernottamento."; pt = "Visita ao Grande Bazar pela manhã, depois viagem de ônibus (6 h) ou trem de alta velocidade (5 h) para Ancara. Visita ao Anıtkabir (Mausoléu de Atatürk), jantar e pernoite." } }
        @{ day = "4"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "التحرك إلى كابادوكيا (3 ساعات) مروراً بالبحيرة الملحية. في الطريق يتم زيارة إحدى المدن الأرضية القديمة. عند الوصول يتم زيارة ورشة سجاد وخزف."; en = "Travel to Cappadocia (3 hrs) passing by the Salt Lake. En route, visit one of the ancient underground cities. Upon arrival, visit a carpet and ceramic workshop."; es = "Traslado a Capadocia (3 h) pasando por el Lago Salado. En el camino, visita a una de las antiguas ciudades subterráneas. A la llegada, visita a taller de alfombras y cerámica."; it = "Trasferimento in Cappadocia (3 h) passando per il Lago Salato. Durante il percorso, visita a una delle antiche città sotterranee. All'arrivo, visita a un laboratorio di tappeti e ceramica."; pt = "Transfer para a Capadócia (3 h) passando pelo Lago Salgado. No caminho, visita a uma das antigas cidades subterrâneas. Na chegada, visita a uma oficina de tapetes e cerâmica." } }
        @{ day = "5"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "(منطاد اختياري فجراً). جولة تشمل: وادي جوريم، قرية أواتش حصار، وادي الحب، وادي ديرفنت، وادي الصيادين، ووادي الحمام، مع زيارة ورش الأونيكس. (اختياري مساءً: سهرة العروض التراثية)."; en = "(Optional hot air balloon at dawn). Tour including: Göreme Valley, Uçhisar village, Love Valley, Devrent Valley, Pigeon Valley, and Imagination Valley, with a visit to an onyx workshop. (Optional evening: traditional folklore show)."; es = "(Globo aerostático opcional al amanecer). Recorrido: Valle de Göreme, pueblo de Uçhisar, Valle del Amor, Valle de Devrent, Valle de las Palomas y Valle de la Imaginación, con visita a taller de ónix. (Noche opcional: espectáculo folclórico)."; it = "(Mongolfiera opzionale all'alba). Giro include: Valle di Göreme, villaggio di Uçhisar, Valle dell'Amore, Valle di Devrent, Valle dei Piccioni e Valle dell'Immaginazione, con visita a un laboratorio di onice. (Serata opzionale: spettacolo folcloristico)."; pt = "(Balão de ar quente opcional ao amanhecer). Tour inclui: Vale de Göreme, vila de Uçhisar, Vale do Amor, Vale de Devrent, Vale dos Pombos e Vale da Imaginação, com visita a uma oficina de ônix. (Noite opcional: show folclórico)." } }
        @{ day = "6"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "التحرك براً إلى باموكالي (8 ساعات). زيارة الخان القديم (Kervansaray) ومدرجات باموكالي الجيرية ومدينة هيرابوليس الأثرية. زيارة متجر آوتلت ثم الفندق."; en = "Overland to Pamukkale (8 hrs). Visit the ancient caravanserai (Kervansaray), the white travertine terraces of Pamukkale, and the ancient city of Hierapolis. Visit an outlet store, then hotel."; es = "Traslado por carretera a Pamukkale (8 h). Visita al antiguo caravasar (Kervansaray), las terrazas de travertino blanco de Pamukkale y la ciudad antigua de Hierápolis. Visita a tienda outlet, luego al hotel."; it = "Trasferimento via terra a Pamukkale (8 h). Visita all'antico caravanserraglio (Kervansaray), alle terrazze di travertino bianco di Pamukkale e all'antica città di Hierapolis. Visita a un outlet, poi in hotel."; pt = "Viagem terrestre para Pamukkale (8 h). Visita ao antigo caravançará (Kervansaray), aos terraços de travertino branco de Pamukkale e à cidade antiga de Hierápolis. Visita a uma loja outlet, depois hotel." } }
        @{ day = "7"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "التحرك إلى أفسس (3 ساعات) وزيارة المدينة الرومانية (مكتبة سيلسوس، المسرح، معبد هادريان). زيارة بيت مريم العذراء ومصنع جلود. الانتقال للمبيت في إزمير أو كوشاداسي."; en = "Travel to Ephesus (3 hrs) and visit the Roman city (Library of Celsus, Theater, Temple of Hadrian). Visit the House of the Virgin Mary and a leather factory. Transfer to Izmir or Kuşadası for overnight."; es = "Traslado a Éfeso (3 h) y visita a la ciudad romana (Biblioteca de Celso, Teatro, Templo de Adriano). Visita a la Casa de la Virgen María y fábrica de cuero. Traslado a Esmirna o Kuşadası para alojamiento."; it = "Trasferimento a Efeso (3 h) e visita alla città romana (Biblioteca di Celso, Teatro, Tempio di Adriano). Visita alla Casa della Vergine Maria e a una conceria. Trasferimento a Smirne o Kuşadası per pernottamento."; pt = "Transfer para Éfeso (3 h) e visita à cidade romana (Biblioteca de Celso, Teatro, Templo de Adriano). Visita à Casa da Virgem Maria e a uma fábrica de couro. Transfer para Esmirna ou Kuşadası para pernoite." } }
        @{ day = "8"; meals = @{ ar = "إفطار + عشاء"; en = "Breakfast + Dinner"; es = "Desayuno + Cena"; it = "Colazione + Cena"; pt = "Café da manhã + Jantar" }; description = @{ ar = "التحرك لزيارة مدينة برغامة الأثرية (مشفى أسكليبيون القديم) (ساعتان). ثم التحرك إلى مدينة طروادة التاريخية (3 ساعات). الوصول لتشاناق قلعة للمبيت."; en = "Travel to visit the ancient city of Pergamon (Asclepion ancient hospital) (2 hrs). Then travel to the historic city of Troy (3 hrs). Arrive in Çanakkale for overnight."; es = "Traslado para visitar la antigua ciudad de Pérgamo (Asclepeion, antiguo hospital) (2 h). Luego traslado a la ciudad histórica de Troya (3 h). Llegada a Çanakkale para alojamiento."; it = "Trasferimento per visitare l'antica città di Pergamo (Asclepeion, antico ospedale) (2 h). Poi trasferimento alla storica città di Troia (3 h). Arrivo a Çanakkale per pernottamento."; pt = "Transfer para visitar a antiga cidade de Pérgamo (Asclepeion, antigo hospital) (2 h). Depois transfer para a histórica cidade de Troia (3 h). Chegada a Çanakkale para pernoite." } }
        @{ day = "9"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "التحرك إلى مدينة بورصة (3 ساعات) وعبور جسر عثمان غازي. زيارة الجامع الكبير، الجامع الأخضر، والضريح الأخضر مع التوقف عند متجر الحلقوم. إكمال الطريق لإسطنبول."; en = "Travel to Bursa (3 hrs) crossing the Osman Gazi Bridge. Visit the Grand Mosque, Green Mosque, and Green Tomb, with a stop at a Turkish delight shop. Continue to Istanbul."; es = "Traslado a Bursa (3 h) cruzando el puente Osman Gazi. Visita a la Gran Mezquita, Mezquita Verde y Tumba Verde, con parada en tienda de delizia turca. Continuación a Estambul."; it = "Trasferimento a Bursa (3 h) attraversando il ponte Osman Gazi. Visita alla Grande Moschea, Moschea Verde e Tomba Verde, con sosta in un negozio di lokum. Proseguimento per Istanbul."; pt = "Transfer para Bursa (3 h) atravessando a ponte Osman Gazi. Visita à Grande Mesquita, Mesquita Verde e Túmulo Verde, com parada em uma loja de delícias turcas. Continuação para Istambul." } }
        @{ day = "10"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "يوم حر بالكامل في إسطنبول للاسترخاء والتسوق (أو جولة اختيارية كلاسيكية)."; en = "Completely free day in Istanbul for relaxation and shopping (or optional classic tour)."; es = "Día completamente libre en Estambul para relajarse y comprar (o tour clásico opcional)."; it = "Giornata completamente libera a Istanbul per relax e shopping (o tour classico opzionale)."; pt = "Dia completamente livre em Istambul para relaxar e fazer compras (ou tour clássico opcional)." } }
        @{ day = "11"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "النقل للمطار للمغادرة النهائية."; en = "Transfer to airport for final departure."; es = "Traslado al aeropuerto para la salida final."; it = "Trasferimento in aeroporto per la partenza finale."; pt = "Transfer para o aeroporto para partida final." } }
    )
}

# ===== PROGRAM 2: REG-02 =====
Add-Program @{
    id = "REG-02"
    code = @{ ar = "REG-02"; en = "REG-02"; es = "REG-02"; it = "REG-02"; pt = "REG-02" }
    name = @{ ar = "أفضل ما في إسطنبول"; en = "Best of Istanbul"; es = "Lo Mejor de Estambul"; it = "Il Meglio di Istanbul"; pt = "O Melhor de Istambul" }
    duration = @{ ar = "4 أيام / 3 ليالٍ"; en = "4 days / 3 nights"; es = "4 días / 3 noches"; it = "4 giorni / 3 notti"; pt = "4 dias / 3 noites" }
    minPax = @{ ar = "فردان"; en = "2 Pax"; es = "2 Pax"; it = "2 Pax"; pt = "2 Pax" }
    overview = @{
        ar = "برنامج مكثف ومثالي للمسافرين الذين يرغبون في الغوص في سحر عاصمة الإمبراطوريات الثلاث (إسطنبول) دون مغادرتها. يركز البرنامج على المواقع التاريخية الكبرى للبلد في جولات منظمة مريحة مع توفير وقت حر للتسوق والاستكشاف الشخصي."
        en = "An intensive, ideal program for travelers who want to dive into the magic of the capital of three empires (Istanbul) without leaving it. The program focuses on the city's major historical sites through comfortable organized tours, with free time for shopping and personal exploration."
        es = "Un programa intensivo e ideal para viajeros que desean sumergirse en la magia de la capital de tres imperios (Estambul) sin salir de ella. El programa se centra en los grandes sitios históricos de la ciudad mediante visitas organizadas y cómodas, con tiempo libre para compras y exploración personal."
        it = "Un programma intensivo e ideale per i viaggiatori che vogliono immergersi nella magia della capitale di tre imperi (Istanbul) senza allontanarsi. Il programma si concentra sui principali siti storici della città con tour organizzati e confortevoli, con tempo libero per shopping ed esplorazione personale."
        pt = "Um programa intensivo e ideal para viajantes que desejam mergulhar na magia da capital de três impérios (Istambul) sem sair dela. O programa foca nos principais sítios históricos da cidade através de passeios organizados e confortáveis, com tempo livre para compras e exploração pessoal."
    }
    highlights = @{
        ar = @("جولة تاريخية شاملة لأيقونة المعمار البيزنطي والإسلامي ""آيا صوفيا"".","دخول حصري لأجنحة قصر توبكابي الملكي مع تذكرة ""الحرملك"".","تأمل التصاميم الزرقاء الفريدة لستة مآذن في المسجد الأزرق.","التسوق واقتناء التذكارات من بين متاجر الجراند بازار التاريخي.")
        en = @("Comprehensive historical tour of the icon of Byzantine and Islamic architecture — Hagia Sophia.","Exclusive access to the royal chambers of Topkapi Palace with the ""Harem"" ticket.","Admire the unique blue designs of the six-minaret Blue Mosque.","Shopping and finding souvenirs among the shops of the historic Grand Bazaar.")
        es = @("Recorrido histórico completo por el ícono de la arquitectura bizantina e islámica — Santa Sofía.","Acceso exclusivo a las estancias reales del Palacio de Topkapi con entrada al Harén.","Contemplar los singulares diseños azules de las seis torres de la Mezquita Azul.","Comprar y adquirir recuerdos entre las tiendas del histórico Gran Bazar.")
        it = @("Tour storico completo dell'icona dell'architettura bizantina e islamica — Santa Sofia.","Accesso esclusivo agli appartamenti reali del Palazzo di Topkapi con il biglietto dell'Harem.","Ammirare i caratteristici disegni blu della Moschea Blu con i suoi sei minareti.","Shopping e souvenir tra i negozi del storico Gran Bazar.")
        pt = @("Tour histórico completo do ícone da arquitetura bizantina e islâmica — Santa Sofia.","Acesso exclusivo aos aposentos reais do Palácio de Topkapi com o ingresso do Harém.","Contemplar os designs azuis únicos da Mesquita Azul com seus seis minaretes.","Compras e lembranças entre as lojas do histórico Grande Bazar.")
    }
    days = @(
        @{ day = "1"; meals = $null; description = @{ ar = "الوصول إلى مطار إسطنبول والنقل إلى الفندق والمبيت."; en = "Arrival at Istanbul Airport and transfer to hotel. Overnight."; es = "Llegada al aeropuerto de Estambul y traslado al hotel. Alojamiento."; it = "Arrivo all'aeroporto di Istanbul e trasferimento in hotel. Pernottamento."; pt = "Chegada ao aeroporto de Istambul e transfer para o hotel. Pernoitada." } }
        @{ day = "2"; meals = @{ ar = "إفطار + غداء"; en = "Breakfast + Lunch"; es = "Desayuno + Almuerzo"; it = "Colazione + Pranzo"; pt = "Café da manhã + Almoço" }; description = @{ ar = "جولة كاملة بالمدينة تشمل: آيا صوفيا (خارجياً)، وقصر توبكابي (شامل الحرملك)، والمسجد الأزرق، وميدان سباق الخيل الروماني (الهيبودروم)، وتختم بوقت حر في الجراند بازار."; en = "Full city tour including: Hagia Sophia (exterior), Topkapi Palace (including Harem), Blue Mosque, Roman Hippodrome, ending with free time at the Grand Bazaar."; es = "Recorrido completo por la ciudad: Santa Sofía (exterior), Palacio de Topkapi (incluyendo el Harén), Mezquita Azul, Hipódromo romano, y tiempo libre en el Gran Bazar."; it = "Giro completo della città: Santa Sofia (esterno), Palazzo di Topkapi (incluso Harem), Moschea Blu, Ippodromo romano, e tempo libero al Gran Bazar."; pt = "Tour completo pela cidade: Santa Sofia (exterior), Palácio de Topkapi (incluindo Harém), Mesquita Azul, Hipódromo romano, e tempo livre no Grande Bazar." } }
