        es = @("Visita al histórico Bazar de las Especias en el antiguo barrio de Eminönü en Estambul.","Tomar fotos impresionantes sobre el Lago Salado mientras se viaja a Ankara.","Visitar los increíbles teatros romanos y las antiguas bibliotecas en la ciudad arqueológica de Éfeso.","Oportunidad de peregrinar y bendecirse visitando la sagrada Casa de la Virgen María en el Monte Bülbül.")
        it = @("Visita allo storico Bazar delle Spezie nell'antico quartiere di Eminönü a Istanbul.","Scattare foto mozzafiato sul Lago Salato durante il viaggio verso Ankara.","Visitare gli incredibili teatri romani e le antiche biblioteche nella città archeologica di Efeso.","Opportunità di pellegrinaggio alla sacra Casa della Vergine Maria sul Monte Bülbül.")
        pt = @("Visita ao histórico Bazar de Especiarias no antigo bairro de Eminönü em Istambul.","Tirar fotos impressionantes sobre o Lago Salgado durante o trajeto para Ancara.","Visitar os incríveis teatros romanos e as antigas bibliotecas na cidade arqueológica de Éfeso.","Oportunidade de peregrinação e bênção visitando a sagrada Casa da Virgem Maria no Monte Bülbül.")
