    duration = @{ ar = "8 أيام / 7 ليالٍ"; en = "8 days / 7 nights"; es = "8 días / 7 noches"; it = "8 giorni / 7 notti"; pt = "8 dias / 7 noites" }
    minPax = @{ ar = "فردان"; en = "2 Pax"; es = "2 Pax"; it = "2 Pax"; pt = "2 Pax" }
    overview = @{
        ar = "رحلة تركز بشكل أساسي على الوجهتين الأكثر شهرة وسحراً في تركيا: عاصفة الألوان في إسطنبول والمناظر القمرية الخيالية في كابادوكيا. يتميز البرنامج بدمج المسار البري في الذهاب مع توفير طيران داخلي مريح في العودة لاختصار الوقت والاستمتاع بإسطنبول."
        en = "A journey focused primarily on Turkey's two most famous and magical destinations: the whirlwind of colors in Istanbul and the fairytale lunar landscapes of Cappadocia. The program combines an overland outbound route with a comfortable domestic flight for the return to save time and enjoy Istanbul."
        es = "Un viaje centrado principalmente en los dos destinos más famosos y mágicos de Turquía: el torbellino de colores de Estambul y los paisajes lunares de ensueño de Capadocia. El programa combina la ruta terrestre de ida con un cómodo vuelo interno de regreso para ahorrar tiempo y disfrutar de Estambul."
        it = "Un viaggio incentrato principalmente sulle due destinazioni più famose e magiche della Turchia: il vortice di colori di Istanbul e i paesaggi lunari da favola della Cappadocia. Il programma combina il percorso via terra all'andata con un comodo volo interno per il ritorno per risparmiare tempo e godersi Istanbul."
        pt = "Uma viagem focada principalmente nos dois destinos mais famosos e mágicos da Turquia: o turbilhão de cores de Istambul e as paisagens lunares de contos de fadas da Capadócia. O programa combina a rota terrestre de ida com um voo doméstico confortável para a volta, economizando tempo e aproveitando Istambul."
    }
    highlights = @{
        ar = @("الإبحار بمركب في جولة اختيارية مميزة عبر مضيق البوسفور.","استكشاف الكنائس الروك ومتاحف الوديان في صخور التوفا البركانية بوادي جوريم.","الاستمتاع ببانوراما المناظر الطبيعية من أعلى القلعة الصخرية في أواتش حصار.","توفير وقت طيران داخلي مريح للعودة من كابادوكيا إلى إسطنبول مباشرة.")
        en = @("Sail on a regular boat on an optional special Bosphorus cruise.","Explore the rock-hewn churches and valley museums in the volcanic tuff rocks of Göreme Valley.","Enjoy the panoramic landscapes from the top of the rock castle in Uçhisar.","A comfortable domestic flight from Cappadocia directly back to Istanbul.")
        es = @("Navegar en una embarcación regular en un exclusivo crucero opcional por el Bósforo.","Explorar las iglesias rupestres y los museos de los valles en las rocas de toba volcánica del Valle de Göreme.","Disfrutar de la panorámica de los paisajes desde lo alto del castillo rocoso de Uçhisar.","Un cómodo vuelo nacional de regreso desde Capadocia directamente a Estambul.")
        it = @("Navigare su un'imbarcazione regolare in un'esclusiva crociera opzionale sul Bosforo.","Esplorare le chiese rupestri e i musei delle valli nelle rocce di tufo vulcanico della Valle di Göreme.","Godere della panoramica dei paesaggi dalla cima del castello roccioso di Uçhisar.","Un comodo volo interno di ritorno dalla Cappadocia direttamente a Istanbul.")
        pt = @("Navegar em uma embarcação regular em um cruzeiro opcional exclusivo pelo Bósforo.","Explorar as igrejas escavadas na rocha e os museus dos vales nas rochas de tufo vulcânico do Vale de Göreme.","Desfrutar da panorâmica das paisagens do alto do castelo rochoso de Uçhisar.","Um voo doméstico confortável de volta da Capadócia diretamente para Istambul.")
    }
    days = @(
        @{ day = "1–5"; meals = $null; description = @{ ar = "تتطابق تماماً مع مسار رحلة ""تركيا الأسطورية براً"" والوجبات المحددة فيها."; en = "Fully match the route and specified meals of the ""Legendary Turkey"" overland program."; es = "Coinciden completamente con el recorrido y las comidas del programa ""Turquía Legendaria"" por tierra."; it = "Corrispondono perfettamente al percorso e ai pasti del programma ""Turchia Leggendaria"" via terra."; pt = "Correspondem exatamente ao percurso e às refeições do programa ""Turquia Legendária"" por terra." } }
        @{ day = "6"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "النقل إلى مطار كابادوكيا واستقلال طائرة والعودة طيراناً إلى إسطنبول، ثم الانتقال للفندق."; en = "Transfer to Cappadocia airport, take a flight back to Istanbul, then transfer to hotel."; es = "Traslado al aeropuerto de Capadocia, vuelo de regreso a Estambul, luego traslado al hotel."; it = "Trasferimento all'aeroporto della Cappadocia, volo di ritorno a Istanbul, poi trasferimento in hotel."; pt = "Transfer para o aeroporto da Capadócia, voo de volta para Istambul, depois transfer para o hotel." } }
        @{ day = "7"; meals = @{ ar = "إفطار"; en = "Breakfast"; es = "Desayuno"; it = "Colazione"; pt = "Café da manhã" }; description = @{ ar = "يوم حر في إسطنبول، أو الانضمام لرحلة اختيارية كاملة للمدينة القديمة (آيا صوفيا خارجي، توبكابي، والمسجد الأزرق)."; en = "Free day in Istanbul, or join an optional full Old City tour (Hagia Sophia exterior, Topkapi Palace, Blue Mosque)."; es = "Día libre en Estambul, o unirse a un tour opcional completo de la Ciudad Vieja (Santa Sofía exterior, Topkapi, Mezquita Azul)."; it = "Giornata libera a Istanbul, o partecipare a un tour opzionale completo della Città Vecchia (Santa Sofia esterno, Topkapi, Moschea Blu)."; pt = "Dia livre em Istambul, ou participar de um tour opcional completo pela Cidade Velha (Santa Sofia exterior, Topkapi, Mesquita Azul)." } }
